function seedTable(table, rows) {
  if (!rows || rows.length === 0) return;
  const count = db.prepare('SELECT COUNT(*) as c FROM ' + table).get().c;
  if (count > 0) return;
  console.log('Seeding ' + table + ' (' + rows.length + ' rows)...');
  const cols = Object.keys(rows[0]);
  const stmt = db.prepare('INSERT OR IGNORE INTO ' + table + ' (' + cols.join(', ') + ') VALUES (' + cols.map(() => '?').join(', ') + ')');
  db.transaction((items) => { for (const row of items) stmt.run(cols.map(c => row[c] !== undefined ? row[c] : null)); })(rows);
}

