// Spawn the server as a child process to avoid SQLite WAL lock conflicts
const { spawn } = require('child_process');
const server = spawn(process.execPath, ['dist/index.cjs'], {
  stdio: 'inherit',
  cwd: __dirname,
  env: { ...process.env, NODE_ENV: process.env.NODE_ENV || 'production' }
});
server.on('error', (err) => { console.error('Server failed to start:', err); process.exit(1); });
server.on('exit', (code) => { if (code !== 0) process.exit(code); });
